import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import './Courses.css';

const Courses = () => {
  const [courses, setCourses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedCategory, setSelectedCategory] = useState('all');
  const { user } = useAuth();

  const courseCategories = [
    'all', 'technology', 'business', 'design', 'data-science', 
    'marketing', 'healthcare', 'finance', 'engineering', 
    'creative-arts', 'education', 'personal-development'
  ];

  useEffect(() => {
    fetchCourses();
  }, []);

  const fetchCourses = async () => {
    setLoading(true);
    try {
      const comprehensiveCourses = [
        // Technology Courses
        { id: 1, title: 'Web Development Bootcamp', platform: 'Udemy', category: 'technology', duration: '40h', level: 'All', rating: 4.7, students: '1.5M', price: '$89.99', image: 'https://img-c.udemycdn.com/course/240x135/1565838_e54e_16.jpg', link: '#', skills: ['HTML', 'CSS', 'JS'] },
        { id: 2, title: 'Python for Everybody', platform: 'Coursera', category: 'technology', duration: '3mo', level: 'Beginner', rating: 4.8, students: '1.2M', price: 'Free', image: 'https://img-c.udemycdn.com/course/240x135/903744_8eb2.jpg', link: '#', skills: ['Python', 'Programming'] },
        { id: 3, title: 'AWS Cloud Practitioner', platform: 'AWS', category: 'technology', duration: '6h', level: 'Beginner', rating: 4.6, students: '800K', price: 'Free', image: 'https://img-c.udemycdn.com/course/240x135/3148696_4e81_3.jpg', link: '#', skills: ['AWS', 'Cloud'] },
        { id: 4, title: 'React Masterclass', platform: 'Udemy', category: 'technology', duration: '35h', level: 'Intermediate', rating: 4.7, students: '450K', price: '$74.99', image: 'https://img-c.udemycdn.com/course/240x135/1362070_b8a1_2.jpg', link: '#', skills: ['React', 'Redux'] },
        { id: 5, title: 'Java Programming', platform: 'Coursera', category: 'technology', duration: '4mo', level: 'Beginner', rating: 4.6, students: '600K', price: 'Free', image: 'https://img-c.udemycdn.com/course/240x135/827692_91ad_2.jpg', link: '#', skills: ['Java', 'OOP'] },

        // Data Science Courses
        { id: 6, title: 'Machine Learning', platform: 'Coursera', category: 'data-science', duration: '3mo', level: 'Intermediate', rating: 4.8, students: '500K', price: 'Free', image: 'https://img-c.udemycdn.com/course/240x135/950390_270f_3.jpg', link: '#', skills: ['Python', 'ML'] },
        { id: 7, title: 'Data Science', platform: 'edX', category: 'data-science', duration: '9mo', level: 'Intermediate', rating: 4.5, students: '300K', price: '$356', image: 'https://img-c.udemycdn.com/course/240x135/1754098_e0df_3.jpg', link: '#', skills: ['R', 'Stats'] },
        { id: 8, title: 'SQL Database', platform: 'Udemy', category: 'data-science', duration: '20h', level: 'Beginner', rating: 4.6, students: '350K', price: '$59.99', image: 'https://img-c.udemycdn.com/course/240x135/1906852_0c6e_5.jpg', link: '#', skills: ['SQL', 'Database'] },
        { id: 9, title: 'Data Visualization', platform: 'Coursera', category: 'data-science', duration: '2mo', level: 'Beginner', rating: 4.5, students: '200K', price: 'Free', image: 'https://img-c.udemycdn.com/course/240x135/2480346_3023_3.jpg', link: '#', skills: ['Tableau', 'Viz'] },
        { id: 10, title: 'Big Data Analytics', platform: 'edX', category: 'data-science', duration: '5mo', level: 'Advanced', rating: 4.4, students: '150K', price: '$299', image: 'https://img-c.udemycdn.com/course/240x135/1327382_6a16_5.jpg', link: '#', skills: ['Hadoop', 'Spark'] },

        // Business Courses
        { id: 11, title: 'Business Foundations', platform: 'Coursera', category: 'business', duration: '6mo', level: 'Beginner', rating: 4.7, students: '400K', price: 'Free', image: 'https://img-c.udemycdn.com/course/240x135/3510304_8f5c_3.jpg', link: '#', skills: ['Marketing', 'Finance'] },
        { id: 12, title: 'Project Management', platform: 'Google', category: 'business', duration: '6mo', level: 'Beginner', rating: 4.6, students: '600K', price: '$39/mo', image: 'https://img-c.udemycdn.com/course/240x135/3968766_5d3a_4.jpg', link: '#', skills: ['Planning', 'PM'] },
        { id: 13, title: 'Digital Marketing', platform: 'Google', category: 'business', duration: '40h', level: 'Beginner', rating: 4.5, students: '800K', price: 'Free', image: 'https://img-c.udemycdn.com/course/240x135/914296_3670_8.jpg', link: '#', skills: ['SEO', 'Social'] },
        { id: 14, title: 'Leadership Skills', platform: 'Coursera', category: 'business', duration: '1mo', level: 'All', rating: 4.6, students: '250K', price: 'Free', image: 'https://img-c.udemycdn.com/course/240x135/433126_3ec5_3.jpg', link: '#', skills: ['Leadership', 'Team'] },
        { id: 15, title: 'Entrepreneurship', platform: 'Udemy', category: 'business', duration: '15h', level: 'Beginner', rating: 4.5, students: '180K', price: '$49.99', image: 'https://img-c.udemycdn.com/course/240x135/1576856_9aeb_4.jpg', link: '#', skills: ['Startup', 'Business'] },

        // Design Courses
        { id: 16, title: 'UI/UX Design', platform: 'Coursera', category: 'design', duration: '6mo', level: 'Beginner', rating: 4.6, students: '300K', price: 'Free', image: 'https://img-c.udemycdn.com/course/240x135/1650610_6654_3.jpg', link: '#', skills: ['Figma', 'UI/UX'] },
        { id: 17, title: 'Graphic Design', platform: 'Udemy', category: 'design', duration: '15h', level: 'All', rating: 4.7, students: '250K', price: '$84.99', image: 'https://img-c.udemycdn.com/course/240x135/1643044_299d_5.jpg', link: '#', skills: ['Photoshop', 'Design'] },
        { id: 18, title: 'Web Design', platform: 'Udemy', category: 'design', duration: '25h', level: 'Beginner', rating: 4.6, students: '220K', price: '$69.99', image: 'https://img-c.udemycdn.com/course/240x135/1453444_00a9_3.jpg', link: '#', skills: ['CSS', 'Design'] },
        { id: 19, title: 'Figma for Beginners', platform: 'Coursera', category: 'design', duration: '1mo', level: 'Beginner', rating: 4.5, students: '150K', price: 'Free', image: 'https://img-c.udemycdn.com/course/240x135/1754002_6c0d_2.jpg', link: '#', skills: ['Figma', 'Prototype'] },
        { id: 20, title: 'Adobe Illustrator', platform: 'Udemy', category: 'design', duration: '12h', level: 'Beginner', rating: 4.6, students: '190K', price: '$59.99', image: 'https://img-c.udemycdn.com/course/240x135/1045092_8c2f_6.jpg', link: '#', skills: ['Illustrator', 'Vector'] },

        // Healthcare Courses
        { id: 21, title: 'Public Health', platform: 'Coursera', category: 'healthcare', duration: '15h', level: 'Beginner', rating: 4.7, students: '150K', price: 'Free', image: 'https://img-c.udemycdn.com/course/240x135/2480346_3023_3.jpg', link: '#', skills: ['Health', 'Policy'] },
        { id: 22, title: 'Anatomy & Physiology', platform: 'Coursera', category: 'healthcare', duration: '4mo', level: 'Beginner', rating: 4.8, students: '200K', price: 'Free', image: 'https://img-c.udemycdn.com/course/240x135/828006_0a25_5.jpg', link: '#', skills: ['Anatomy', 'Medical'] },
        { id: 23, title: 'Nutrition Science', platform: 'edX', category: 'healthcare', duration: '2mo', level: 'Beginner', rating: 4.5, students: '120K', price: 'Free', image: 'https://img-c.udemycdn.com/course/240x135/751902_0e89_5.jpg', link: '#', skills: ['Nutrition', 'Health'] },
        { id: 24, title: 'Mental Health First Aid', platform: 'Coursera', category: 'healthcare', duration: '10h', level: 'Beginner', rating: 4.6, students: '180K', price: 'Free', image: 'https://img-c.udemycdn.com/course/240x135/3147464_8f3e_4.jpg', link: '#', skills: ['Mental Health', 'Aid'] },
        { id: 25, title: 'Healthcare Management', platform: 'edX', category: 'healthcare', duration: '3mo', level: 'Intermediate', rating: 4.4, students: '90K', price: '$199', image: 'https://img-c.udemycdn.com/course/240x135/4051320_3aa3_3.jpg', link: '#', skills: ['Management', 'Healthcare'] },

        // Finance Courses
        { id: 26, title: 'Financial Markets', platform: 'Coursera', category: 'finance', duration: '33h', level: 'Beginner', rating: 4.8, students: '400K', price: 'Free', image: 'https://img-c.udemycdn.com/course/240x135/1754002_6c0d_2.jpg', link: '#', skills: ['Investment', 'Finance'] },
        { id: 27, title: 'Corporate Finance', platform: 'edX', category: 'finance', duration: '6wk', level: 'Beginner', rating: 4.5, students: '180K', price: 'Free', image: 'https://img-c.udemycdn.com/course/240x135/1453444_00a9_3.jpg', link: '#', skills: ['Finance', 'Corporate'] },
        { id: 28, title: 'Personal Finance', platform: 'Udemy', category: 'finance', duration: '8h', level: 'Beginner', rating: 4.6, students: '220K', price: '$49.99', image: 'https://img-c.udemycdn.com/course/240x135/433126_3ec5_3.jpg', link: '#', skills: ['Budgeting', 'Finance'] },
        { id: 29, title: 'Investment Banking', platform: 'Coursera', category: 'finance', duration: '4mo', level: 'Intermediate', rating: 4.5, students: '150K', price: 'Free', image: 'https://img-c.udemycdn.com/course/240x135/1576856_9aeb_4.jpg', link: '#', skills: ['Banking', 'Investment'] },
        { id: 30, title: 'Cryptocurrency Trading', platform: 'Udemy', category: 'finance', duration: '12h', level: 'Beginner', rating: 4.4, students: '130K', price: '$79.99', image: 'https://img-c.udemycdn.com/course/240x135/1327382_6a16_5.jpg', link: '#', skills: ['Crypto', 'Trading'] }
      ];
      
      setCourses(comprehensiveCourses);
    } catch (error) {
      console.error('Error fetching courses:', error);
    } finally {
      setLoading(false);
    }
  };

  const filteredCourses = selectedCategory === 'all' 
    ? courses 
    : courses.filter(course => course.category === selectedCategory);

  const enrollCourse = (courseLink) => {
    window.open(courseLink, '_blank');
  };

  const getCategoryIcon = (category) => {
    const icons = {
      'technology': '💻', 'business': '💼', 'design': '🎨', 'data-science': '📊',
      'marketing': '📱', 'healthcare': '🏥', 'finance': '💰', 'engineering': '⚙️',
      'creative-arts': '🎭', 'education': '📚', 'personal-development': '🌟', 'all': '📚'
    };
    return icons[category] || '📚';
  };

  if (!user) {
    return (
      <div className="courses-container">
        <div className="container">
          <div className="auth-required">
            <h2>Authentication Required</h2>
            <p>Please log in to explore courses.</p>
          </div>
        </div>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="courses-container">
        <div className="container">
          <div className="loading">
            <div className="spinner"></div>
            <p>Loading course catalog...</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="courses-container">
      <div className="container">
        {/* Compact Header */}
        <div className="courses-header">
          <h1>📚 Course Catalog</h1>
          <p>Explore courses across all domains</p>
        </div>

        {/* Compact Filters */}
        <div className="courses-filters">
          <div className="filter-buttons">
            {courseCategories.map(category => (
              <button
                key={category}
                className={`filter-btn ${selectedCategory === category ? 'active' : ''}`}
                onClick={() => setSelectedCategory(category)}
                title={category.replace('-', ' ')}
              >
                {getCategoryIcon(category)}
                <span className="btn-text">
                  {category === 'all' ? 'All' : category.charAt(0).toUpperCase() + category.slice(1).replace('-', ' ')}
                </span>
              </button>
            ))}
          </div>
        </div>

        {/* Course Counter */}
        <div className="courses-counter">
          <span>{filteredCourses.length} courses in {selectedCategory === 'all' ? 'All Domains' : selectedCategory.replace('-', ' ')}</span>
        </div>

        {/* 5 Courses Per Row Grid */}
        <div className="courses-grid five-per-row">
          {filteredCourses.map(course => (
            <div key={course.id} className="course-card ultra-compact">
              <div className="course-image">
                <img src={course.image} alt={course.title} />
                <span className="platform-badge">{course.platform}</span>
              </div>
              
              <div className="course-content">
                <h3 title={course.title}>{course.title}</h3>
                
                <div className="course-meta">
                  <span className="rating">⭐ {course.rating}</span>
                  <span className="students">👥 {course.students}</span>
                </div>

                <div className="course-skills">
                  <div className="skills-tags">
                    {course.skills.slice(0, 2).map((skill, index) => (
                      <span key={index} className="skill-tag">{skill}</span>
                    ))}
                  </div>
                </div>

                <div className="course-footer">
                  <div className="course-info">
                    <span className="duration">{course.duration}</span>
                    <span className="level">{course.level}</span>
                  </div>
                  <div className="course-pricing">
                    <span className="price">{course.price}</span>
                    <button 
                      onClick={() => enrollCourse(course.link)}
                      className="btn enroll-btn"
                    >
                      Enroll
                    </button>
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>

        {filteredCourses.length === 0 && (
          <div className="no-courses">
            <h3>No courses found</h3>
            <p>Try selecting a different category</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Courses;
